 130→void verify_console_object()
 131→{
 132→#ifdef USE_OX_BRIDGE
 133→	if (cd_ox_is_ready()) {
 134→		static int vco_reg = 0;
 135→		if (!vco_reg) {
 136→			vco_reg = 1;
 137→			cd_ox_register_verify_console_object_effects(
 138→				/* fetch: [Player_num, objnum, obj_type, obj_id] */
 139→				[](int32_t* out) {
 140→					out[0] = Player_num;
 141→					out[1] = Players[Player_num].objnum;
 142→					int objnum = Players[Player_num].objnum;
 143→					out[2] = (objnum >= 0) ? Objects[objnum].type : -1;
 144→					out[3] = (objnum >= 0) ? Objects[objnum].id : -1;
 145→				},
 146→				/* write: set ConsoleObject = &Objects[objnum] */
 147→				[](int objnum) {
 148→					ConsoleObject = &Objects[objnum];
 149→				});
 150→		}
 151→		cd_ox_verify_console_object();
 152→		return;
 153→	}
 154→#endif
 155→	Assert(Player_num > -1);
 156→	Assert(Players[Player_num].objnum > -1);
 157→	ConsoleObject = &Objects[Players[Player_num].objnum];
 158→	Assert(ConsoleObject->type == OBJ_PLAYER);
 159→	Assert(ConsoleObject->id == Player_num);
 160→}
