 162→int count_number_of_robots()
 163→{
 164→	int robot_count;
 165→	int i;
 166→
 167→	robot_count = 0;
 168→	for (i = 0; i <= Highest_object_index; i++) 
 169→	{
 170→		if (Objects[i].type == OBJ_ROBOT)
 171→			robot_count++;
 172→	}
 173→
 174→	return robot_count;
 175→}
