 194→void gameseq_init_network_players()
 195→{
 196→	int i, k, j;
 197→
 198→	// Initialize network player start locations and object numbers
 199→
 200→	ConsoleObject = &Objects[0];
 201→	k = 0;
 202→	j = 0;
 203→	for (i = 0; i <= Highest_object_index; i++) 
 204→	{
 205→		if ((Objects[i].type == OBJ_PLAYER) || (Objects[i].type == OBJ_GHOST) || (Objects[i].type == OBJ_COOP))
 206→		{
 207→#ifndef SHAREWARE
 208→			if ((!(Game_mode & GM_MULTI_COOP) && ((Objects[i].type == OBJ_PLAYER) || (Objects[i].type == OBJ_GHOST))) ||
 209→				((Game_mode & GM_MULTI_COOP) && ((j == 0) || (Objects[i].type == OBJ_COOP))))
 210→			{
 211→				mprintf((0, "Created Cooperative multiplayer object\n"));
 212→				Objects[i].type = OBJ_PLAYER;
 213→#endif
 214→				mprintf((0, "Player init %d is ship %d.\n", k, j));
 215→				Player_init[k].pos = Objects[i].pos;
 216→				Player_init[k].orient = Objects[i].orient;
 217→				Player_init[k].segnum = Objects[i].segnum;
 218→				Players[k].objnum = i;
 219→				Objects[i].id = k;
 220→				k++;
 221→#ifndef SHAREWARE
 222→			}
 223→			else
 224→				obj_delete(i);
 225→			j++;
 226→#endif
 227→		}
 228→	}
 229→	NumNetPlayerPositions = k;
 230→
 231→#ifndef NDEBUG
 232→	if (((Game_mode & GM_MULTI_COOP) && (NumNetPlayerPositions != 4)) ||
 233→		(!(Game_mode & GM_MULTI_COOP) && (NumNetPlayerPositions != 8)))
 234→	{
 235→		mprintf((1, "--NOT ENOUGH MULTIPLAYER POSITIONS IN THIS MINE!--\n"));
 236→		//Int3(); // Not enough positions!!
 237→	}
 238→#endif
 239→}
