 308→void init_ammo_and_energy(void)
 309→{
 310→#ifdef USE_OX_BRIDGE
 311→	if (cd_ox_is_ready()) {
 312→		static int iae_reg = 0;
 313→		if (!iae_reg) {
 314→			iae_reg = 1;
 315→			cd_ox_register_init_ammo_energy_effects(
 316→				/* fetch: [energy, shields, secondary_ammo_0, initial_energy, starting_shields, ndl, difficulty_level] */
 317→				[](int32_t* out) {
 318→					out[0] = Players[Player_num].energy;
 319→					out[1] = Players[Player_num].shields;
 320→					out[2] = Players[Player_num].secondary_ammo[0];
 321→					out[3] = MAX_ENERGY;
 322→					out[4] = MAX_SHIELDS;
 323→					out[5] = NDL;
 324→					out[6] = Difficulty_level;
 325→				},
 326→				/* write: [energy, shields, secondary_ammo_0] */
 327→				[](const int32_t* packed, int len) {
 328→					if (len < 3) return;
 329→					Players[Player_num].energy = packed[0];
 330→					Players[Player_num].shields = packed[1];
 331→					Players[Player_num].secondary_ammo[0] = packed[2];
 332→				});
 333→		}
 334→		cd_ox_init_ammo_and_energy();
 335→		return;
 336→	}
 337→#endif
 338→	if (Players[Player_num].energy < MAX_ENERGY)
 339→		Players[Player_num].energy = MAX_ENERGY;
 340→	if (Players[Player_num].shields < MAX_SHIELDS)
 341→		Players[Player_num].shields = MAX_SHIELDS;
 342→
 343→	if (Players[Player_num].secondary_ammo[0] < 2 + NDL - Difficulty_level)
 344→		Players[Player_num].secondary_ammo[0] = 2 + NDL - Difficulty_level;
 345→}
