 499→void update_player_stats()
 500→{
 501→#ifdef USE_OX_BRIDGE
 502→	if (cd_ox_is_ready()) {
 503→		static int ups_reg = 0;
 504→		if (!ups_reg) {
 505→			ups_reg = 1;
 506→			cd_ox_register_update_player_stats_effects(
 507→				/* fetch: [frame_time, time_level, hours_level, time_total, hours_total] */
