 509→					out[0] = FrameTime;
 510→					out[1] = Players[Player_num].time_level;
 511→					out[2] = Players[Player_num].hours_level;
 512→					out[3] = Players[Player_num].time_total;
 513→					out[4] = Players[Player_num].hours_total;
 514→				},
 515→				/* write: [time_level, hours_level, time_total, hours_total] */
 516→				[](const int32_t* packed, int len) {
 517→					if (len < 4) return;
 518→					Players[Player_num].time_level = packed[0];
 519→					Players[Player_num].hours_level = packed[1];
 520→					Players[Player_num].time_total = packed[2];
 521→					Players[Player_num].hours_total = packed[3];
 522→				});
 523→		}
 524→		cd_ox_update_player_stats();
 525→		return;
 526→	}
 527→#endif
 528→	// I took out this 'if' because it was causing the reactor invul time to be
 529→	// off for players that sit in the death screen. -JS jul 6,95
 530→	//	if (!Player_exploded) {
 531→	Players[Player_num].time_level += FrameTime;	//the never-ending march of time...
 532→	if (Players[Player_num].time_level > i2f(3600))
 533→	{
 534→		Players[Player_num].time_level -= i2f(3600);
 535→		Players[Player_num].hours_level++;
 536→	}
 537→
 538→	Players[Player_num].time_total += FrameTime;	//the never-ending march of time...
 539→	if (Players[Player_num].time_total > i2f(3600))
 540→	{
 541→		Players[Player_num].time_total -= i2f(3600);
 542→		Players[Player_num].hours_total++;
 543→	}
 544→	//	}
 545→
 546→	//	Players[Player_num].energy += FrameTime*Energy_regen_ratio;	//slowly regenerate energy
 547→
 548→	//MK1015:	//slowly reduces player's energy & shields if over max
 549→	//MK1015:
 550→	//MK1015:	if (Players[Player_num].energy > MAX_ENERGY) {
 551→	//MK1015:		Players[Player_num].energy -= FrameTime/8;
 552→	//MK1015:		if (Players[Player_num].energy < MAX_ENERGY)
 553→	//MK1015:			Players[Player_num].energy = MAX_ENERGY;
 554→	//MK1015:	}
 555→	//MK1015:
 556→	//MK1015:	if (Players[Player_num].shields > MAX_SHIELDS) {
 557→	//MK1015:		Players[Player_num].shields -= FrameTime/8;
 558→	//MK1015:		if (Players[Player_num].shields < MAX_SHIELDS)
 559→	//MK1015:			Players[Player_num].shields = MAX_SHIELDS;
 560→	//MK1015:	}
 561→}
