 563→//go through this level and start any eclip sounds
 564→void set_sound_sources()
 565→{
 566→	int segnum, sidenum;
 567→	segment* seg;
 568→
 569→	digi_init_sounds();		//clear old sounds
 570→
 571→	for (seg = &Segments[0], segnum = 0; segnum <= Highest_segment_index; seg++, segnum++)
 572→		for (sidenum = 0; sidenum < MAX_SIDES_PER_SEGMENT; sidenum++) 
 573→		{
 574→			int tm, ec, sn;
 575→
 576→			if ((tm = seg->sides[sidenum].tmap_num2) != 0)
 577→				if ((ec = TmapInfo[tm & 0x3fff].eclip_num) != -1)
 578→					if ((sn = Effects[ec].sound_num) != -1) 
 579→					{
 580→						vms_vector pnt;
 581→
 582→						compute_center_point_on_side(&pnt, seg, sidenum);
 583→						digi_link_sound_to_pos(sn, segnum, sidenum, &pnt, 1, F1_0 / 2);
