 957→	sprintf(m_str[c++], "%s%i\n", TXT_TOTAL_BONUS, shield_points + energy_points + hostage_points + skill_points + all_hostage_points + endgame_points);
 958→	sprintf(m_str[c++], "%s%i", TXT_TOTAL_SCORE, Players[Player_num].score);
 959→
 960→	for (i = 0; i < c; i++) 
 961→	{
 962→		m[i].type = NM_TYPE_TEXT;
 963→		m[i].text = m_str[i];
 964→	}
