 970→
 971→	Assert(c <= N_GLITZITEMS);
 972→
 973→	gr_palette_fade_out(gr_palette, 32, 0);
 974→
 975→	time_out_value = timer_get_approx_seconds() + i2f(60 * 5);
 976→
 977→#ifdef NETWORK
 978→	if (network && (Game_mode & GM_NETWORK))
 979→		newmenu_do2(NULL, title, c, m, network_endlevel_poll2, 0, "MENU.PCX");
