1064→extern void do_end_game(void);
1065→
1066→//from which level each do you get to each secret level 
1067→int Secret_level_table[MAX_SECRET_LEVELS_PER_MISSION];
1068→
1069→//called to go to the next level (if there is one)
1070→//if secret_flag is true, advance to secret level, else next normal one
1071→//	Return true if game over.
1072→int AdvanceLevel(int secret_flag)
1073→{
1074→	Fuelcen_control_center_destroyed = 0;
1075→#ifdef EDITOR
1076→	if (Current_level_num == 0)
1077→		return 0;		//not a real level
1078→#endif
1079→
1080→#ifdef NETWORK
1081→	int result;
1082→	if (Game_mode & GM_MULTI)
1083→	{
1084→		result = multi_endlevel(&secret_flag); // Wait for other players to reach this point
1085→		if (result) // failed to sync
1086→			return (Current_level_num == Last_level);
1087→	}
1088→#endif
1089→
1090→	if (Current_level_num == Last_level) //player has finished the game!
1091→	{
1092→		Function_mode = FMODE_MENU;
1093→		if ((Newdemo_state == ND_STATE_RECORDING) || (Newdemo_state == ND_STATE_PAUSED))
1094→			newdemo_stop_recording();
1095→
1096→		songs_play_song(SONG_ENDGAME, 0);
1097→
1098→		do_end_game();
1099→		return 1;
1100→	}
1101→	else 
1102→	{
1103→
1104→		Next_level_num = Current_level_num + 1;		//assume go to next normal level
1105→
1106→		if (secret_flag) {			//go to secret level instead
1107→			int i;
1108→
1109→			for (i = 0; i < -Last_secret_level; i++)
1110→				if (Secret_level_table[i] == Current_level_num) {
1111→					Next_level_num = -(i + 1);
1112→					break;
1113→				}
1114→			Assert(i < -Last_secret_level);		//couldn't find which secret level
1115→		}
1116→
1117→		if (Current_level_num < 0) //on secret level, where to go?
1118→		{			
1119→			Assert(!secret_flag);				//shouldn't be going to secret level
1120→			Assert(Current_level_num <= -1 && Current_level_num >= Last_secret_level);
1121→
1122→			Next_level_num = Secret_level_table[(-Current_level_num) - 1] + 1;
1123→		}
1124→
1125→		if (!(Game_mode & GM_MULTI))
1126→			DoEndlevelMenu(); // Let use save their game
1127→
1128→		StartNewLevel(Next_level_num);
1129→	}
1130→	return 0;
1131→}
