1379→//initialize the player object position & orientation (at start of game, or new ship)
1380→void InitPlayerPosition(int random)
1381→{
1382→	int NewPlayer;
1383→
1384→	if (!((Game_mode & GM_MULTI) && !(Game_mode & GM_MULTI_COOP))) // If not deathmatch
1385→		NewPlayer = Player_num;
1386→#ifdef NETWORK
1387→	else if (random == 1)
1388→	{
1389→		int i, closest = -1, trys = 0;
1390→		fix closest_dist = 0x7ffffff, dist;
1391→
1392→		P_SRand(clock());
1393→
1394→#ifndef NDEBUG
1395→		if (NumNetPlayerPositions != MAX_NUM_NET_PLAYERS)
1396→		{
1397→			mprintf((1, "WARNING: There are only %d start positions!\n"));
1398→			//Int3();
1399→		}
1400→#endif
1401→
1402→		do {
1403→			if (trys > 0)
1404→			{
1405→				mprintf((0, "Can't start in location %d because its too close to player %d\n", NewPlayer, closest));
1406→			}
1407→			trys++;
1408→			NewPlayer = P_Rand() % NumNetPlayerPositions;
1409→
1410→			closest = -1;
1411→			closest_dist = 0x7fffffff;
1412→
1413→			for (i = 0; i < N_players; i++) {
1414→				if ((i != Player_num) && (Objects[Players[i].objnum].type == OBJ_PLAYER)) {
1415→					dist = find_connected_distance(&Objects[Players[i].objnum].pos, Objects[Players[i].objnum].segnum, &Player_init[NewPlayer].pos, Player_init[NewPlayer].segnum, 5, WID_FLY_FLAG);
1416→					//					mprintf((0, "Distance from start location %d to player %d is %f.\n", NewPlayer, i, f2fl(dist)));
1417→					if ((dist < closest_dist) && (dist >= 0)) {
1418→						closest_dist = dist;
1419→						closest = i;
1420→					}
1421→				}
1422→			}
1423→			mprintf((0, "Closest from pos %d is %f to plr %d.\n", NewPlayer, f2fl(closest_dist), closest));
1424→		} while ((closest_dist < i2f(10 * 20)) && (trys < MAX_NUM_NET_PLAYERS * 2));
1425→	}
1426→#endif
1427→	else {
1428→		mprintf((0, "Starting position is not being changed.\n"));
1429→		goto done; // If deathmatch and not random, positions were already determined by sync packet
1430→	}
1431→	Assert(NewPlayer >= 0);
1432→	Assert(NewPlayer < NumNetPlayerPositions);
1433→
1434→	ConsoleObject->pos = Player_init[NewPlayer].pos;
1435→	ConsoleObject->orient = Player_init[NewPlayer].orient;
1436→
1437→	mprintf((0, "Re-starting in location %d of %d.\n", NewPlayer + 1, NumNetPlayerPositions));
1438→
1439→	obj_relink(ConsoleObject - Objects, Player_init[NewPlayer].segnum);
1440→
1441→done:
1442→	reset_player_object();
1443→	reset_cruise();
1444→}
